INSERT INTO public.banners VALUES (1, 'E-Tech Market – Công Nghệ Cho Cuộc Sống', 'Khám phá thế giới công nghệ hiện đại cùng E-Tech Market với hàng ngàn sản phẩm chính hãng từ laptop, PC gaming, linh kiện máy tính đến phụ kiện công nghệ cao cấp. Mang đến trải nghiệm mua sắm nhanh chóng, tiện lợi cùng nhiều ưu đãi hấp dẫn mỗi ngày dành cho khách hàng yêu công nghệ.', '/storage/banners/ebT2uN1yiD5BOdfLBD9UYI7bNeZlr7UNs6KstYbR.jpg', '/products', true, 0, '2026-05-22 10:26:43', '2026-05-22 10:41:17');
INSERT INTO public.banners VALUES (2, 'Blog Công Nghệ E-Tech Market', 'Theo dõi các bài viết nổi bật về laptop, PC gaming, linh kiện máy tính, phụ kiện công nghệ và nhiều chủ đề hấp dẫn khác. Khám phá kiến thức công nghệ hữu ích giúp bạn lựa chọn sản phẩm phù hợp và nâng cao trải nghiệm sử dụng mỗi ngày.', '/storage/banners/7S3GkC1Hh2XaZinJDSCA9PvrZML2D223LYk1Q2AL.png', '/blog', true, 1, '2026-05-22 11:07:16', '2026-05-22 11:07:16');
INSERT INTO public.banners VALUES (3, 'Build PC Theo Ý Bạn', 'Tự do xây dựng cấu hình PC mạnh mẽ với các linh kiện chính hãng như CPU, VGA, RAM, SSD và mainboard từ những thương hiệu hàng đầu. Phù hợp cho nhu cầu gaming, thiết kế đồ họa, livestream và làm việc chuyên nghiệp với hiệu suất tối ưu.', '/storage/banners/UCDNwNw29s2Xwe3ZQGU7N9juIsgCXyB55dTnDJuL.png', '/products?category=linh-kien', true, 2, '2026-05-22 11:11:00', '2026-05-22 11:11:00');


