INSERT INTO public.blog_posts VALUES (1, 1, 11, 'OPPO Find X9 Ultra và Find X9s ra mắt tại Việt Nam, đưa trải nghiệm nhiếp ảnh Hasselblad đến gần hơn với người dùng', 'oppo-find-x9-ultra-va-find-x9s-ra-mat-tai-viet-nam-dua-trai-nghiem-nhiep-anh-hasselblad-den-gan-hon-voi-nguoi-dung-6a01a5656e3be', 'OPPO Find X9 Ultra đại diện cho đỉnh cao công nghệ hình ảnh trên smartphone, trong khi OPPO Find X9s mang đến hướng tiếp cận gần gũi hơn với trải nghiệm nhiếp ảnh Hasselblad chuẩn flagship dành cho người dùng.

OPPO Việt Nam mới đây vừa chính thức ra mắt bộ đôi flagship Find X9 Ultra và Find X9s tại sự kiện “Finding Hội An”. Lấy cảm hứng từ vẻ đẹp thị giác đặc trưng của phố cổ cùng di sản màu sắc đến từ Hasselblad, sự kiện đánh dấu lần đầu tiên dòng sản phẩm flagship Find X9 Series được giới thiệu đầy đủ tại thị trường Việt Nam.', '<article class="w-full rounded-[10px] bg-textWhite p-[5px] w600:rounded-[15px] w600:p-[10px] w600:shadow-gray  w800:p-[15px] w1000:p-[25px]"><div class="mb-[10px]  hidden w-full gap-[10px] w600:flex "><a class="flex h-fit w-fit items-center gap-[5px] rounded-[5px] bg-cps px-[8px] py-[5px] text-textWhite w600:px-[12px]" href="/sforum/tin-cong-nghe"><span class="text-sm font-[600] w600:text-base">Tin công nghệ</span></a></div><h1 class="m-[0px] hidden py-[10px] text-xl font-bold text-textGray w600:inline-block w600:text-2xl w900:text-3xl">OPPO Find X9 Ultra và Find X9s ra mắt tại Việt Nam, đưa trải nghiệm nhiếp ảnh Hasselblad đến gần hơn với người dùng</h1><div class="flex w-full flex-wrap items-center justify-between gap-[10px] py-[10px]"><div class="flex items-center gap-[5px]"><div class="h-[35px] w-[35px] rounded-[50%] border-[1px] border-[#ef1515] p-[2px] w600:h-[40px] w600:w-[40px]"><div class="relative h-full w-full rounded-[50%]"><img alt="SHIRO , Tác giả Sforum - Trang tin công nghệ mới nhất" title="SHIRO , Tác giả Sforum - Trang tin công nghệ mới nhất" loading="lazy" width="80" height="80" decoding="async" data-nimg="1" class="h-full w-full rounded-[50%] object-cover" src="https://cdn-media.sforum.vn/storage/app/media/Profile CTV/411220626_24359146347034056_5111871343617902616_n.jpg" style="color: transparent;"></div></div><div class="flex flex-col gap-[2px]"><a class="text-sm font-[600] text-cps w600:text-base" href="/sforum/author/nhattruong">SHIRO </a><div class=" flex gap-[5px] text-[10px] font-[300] text-[#656565] w600:text-[11px]"><span class="flex items-center gap-[3px]"><svg stroke="currentColor" fill="currentColor" stroke-width="0" viewBox="0 0 24 24" class="text-textBlue" height="15" width="15" xmlns="http://www.w3.org/2000/svg"><path fill="none" d="M0 0h24v24H0V0z"></path><path d="M7 11h2v2H7v-2zm14-5v14c0 1.1-.9 2-2 2H5a2 2 0 01-2-2l.01-14c0-1.1.88-2 1.99-2h1V2h2v2h8V2h2v2h1c1.1 0 2 .9 2 2zM5 8h14V6H5v2zm14 12V10H5v10h14zm-4-7h2v-2h-2v2zm-4 0h2v-2h-2v2z"></path></svg><span>Ngày cập nhật: 09/05/2026</span></span></div></div></div></div><div></div><div class="my-[15px] hidden w-full rounded-[8px] bg-[#f4f7ff] p-[10px] "><div class="my-[20px] h-[0px] w-full rounded-[12px] border-t-[1px] border-dashed border-[#919EAB3D] p-[12px]"></div><div class="mb-[10px] flex w-full flex-col items-end gap-[10px] w800:flex-row w800:items-start"><div class="mt-[10px]"></div><div class="mt-[10px] w-full"><div class="relative h-[14px] w-full rounded-[14px] bg-[#ff9099]"><div class="h-full rounded-[14px] bg-[#cd0017]"></div><div class="z-1 absolute top-[-10px] h-[30px] w-[30px] translate-x-[-20px] object-contain"></div><div class="absolute left-[50%] top-[50%] z-[2] w-[110%] translate-x-[-50%] translate-y-[-50%] text-center text-[11px] font-[800] text-[#fff]"></div></div></div><p class="w-full flex-1 border-[4px] border-[#d51f45] text-base font-[600]"></p><a class="sforum_view_all_product flex flex-shrink-0 items-center font-[600] !text-cps" href=""></a><div class="relative grid w-full grid-cols-2 justify-stretch gap-[5px] overflow-hidden w600:!grid-cols-3 w1000:!grid-cols-4"><div class="px-[2px]"><div class="swiper-slide p-[2px]"><div class="box-border block min-h-[60px] w-full overflow-hidden rounded-[8px] p-[10px] !text-textGray !no-underline shadow-gray hover:!text-cps hover:!no-underline"><div class="m-auto w-full max-w-[150px]"><div class="!m-[0px] aspect-1/1 w-full object-contain"></div></div><div class="line-clamp-2 min-h-[50px] w-full text-ellipsis text-start text-sm w600:text-base"></div><div class="mt-[5px] flex flex-wrap gap-[8px] line-through"></div></div></div></div></div><div class="my-[15px] flex w-full max-w-[200px] flex-shrink-0 flex-col items-center justify-center gap-[10px] overflow-hidden rounded-[10px] border-[1px] border-[#eee] p-[10px] w800:w-[35%] w800:flex-1 "></div><div class="gap-[20px] text-center text-xl font-[600]"></div><div class="aspect-video gap-[5px] rounded-[5px] bg-cps px-[8px] py-[5px] !text-textWhite"></div></div></div><div class="relative mt-[10px] w-full pb-[20px]"><div id="pin-table-content" class="sticky top-[var(--height-header)] z-[999] hidden max-h-[800px] w-[calc(100%+20px)] translate-x-[-10px] w600:w-[calc(100%+50px)] w600:translate-x-[-25px]"><div class="relative w-full"></div></div><div class="content-detail w-full text-textGray w600:mt-[10px]"><div class="w-full"></div><div class="w-full"><p><strong><a href="https://cellphones.com.vn/dien-thoai-oppo-find-x9-ultra.html">OPPO Find X9 Ultra</a> đại diện cho đỉnh cao công nghệ hình ảnh trên <a href="https://cellphones.com.vn/mobile.html" target="_blank">smartphone</a>, trong khi <a href="https://cellphones.com.vn/dien-thoai-oppo-find-x9s.html">OPPO Find X9s</a> mang đến hướng tiếp cận gần gũi hơn với trải nghiệm nhiếp ảnh Hasselblad chuẩn flagship dành cho người dùng.</strong></p>

<p><a href="https://cellphones.com.vn/mobile/oppo.html">OPPO</a> Việt Nam mới đây vừa chính thức ra mắt bộ đôi flagship Find X9 Ultra và Find X9s tại sự kiện “Finding Hội An”. Lấy cảm hứng từ vẻ đẹp thị giác đặc trưng của phố cổ cùng di sản màu sắc đến từ Hasselblad, sự kiện đánh dấu lần đầu tiên dòng sản phẩm flagship Find X9 Series được giới thiệu đầy đủ tại thị trường Việt Nam.</p>

<p style="text-align:center"><img alt="" height="675" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-1.jpg" width="1200"></p>

<div><div class=" table-content my-[15px] rounded-[5px] bg-[#f2f3f7] p-[10px] transition-all w600:p-[15px]"><div class="flex w-full items-center justify-between"><span class="text-base font-[600] text-textGray w600:text-lg">Mục lục</span><button type="button" class="flex cursor-pointer items-center gap-[3px] rounded border-none text-sm font-[500] text-textBlue hover:text-cps w600:text-sm">Ẩn <svg stroke="currentColor" fill="currentColor" stroke-width="0" viewBox="0 0 512 512" height="15" width="15" xmlns="http://www.w3.org/2000/svg"><path d="M256 217.9L383 345c9.4 9.4 24.6 9.4 33.9 0 9.4-9.4 9.3-24.6 0-34L273 167c-9.1-9.1-23.7-9.3-33.1-.7L95 310.9c-4.7 4.7-7 10.9-7 17s2.3 12.3 7 17c9.4 9.4 24.6 9.4 33.9 0l127.1-127z"></path></svg></button></div><ul class="mt-[10px] flex w-full flex-col gap-[8px] overflow-hidden !pl-0 w600:mt-[15px] "><li class="block w-full text-sm font-[500] text-textGray hover:text-textBlue w600:text-base "><a href="#find-x9-ultra-dot-pha-cong-nghe-dinh-hinh-chuan-muc-nhiep-anh-di-dong-cung-dau-an-di-san-hasselblad">1. Find X9 Ultra: Đột phá công nghệ, định hình chuẩn mực nhiếp ảnh di động cùng dấu ấn di sản Hasselblad</a></li><li class="block w-full text-sm font-[500] text-textGray hover:text-textBlue w600:text-base "><a href="#oppo-find-x9s-nguoi-ban-dong-hanh-hasselblad-cua-nhung-chuyen-hanh-trinh-sang-tao-day-cam-hung">2. OPPO Find X9s: Người bạn đồng hành Hasselblad của những chuyến hành trình sáng tạo đầy cảm hứng</a></li><li class="block w-full text-sm font-[500] text-textGray hover:text-textBlue w600:text-base "><a href="#gia-ban-hap-dan">3. Giá bán hấp dẫn</a></li></ul></div></div><h2 id="find-x9-ultra-dot-pha-cong-nghe-dinh-hinh-chuan-muc-nhiep-anh-di-dong-cung-dau-an-di-san-hasselblad" style="scroll-margin : 125px;"><strong>Find X9 Ultra: Đột phá công nghệ, định hình chuẩn mực nhiếp ảnh di động cùng dấu ấn di sản Hasselblad</strong></h2>

<p>Với triết lý không ngừng bứt phá giới hạn, <a href="https://cellphones.com.vn/mobile/oppo/find-x-series.html" target="_blank">OPPO Find</a> X9 Ultra tái định nghĩa nhiếp ảnh di động qua Hệ thống <a href="https://cellphones.com.vn/phu-kien/camera.html" target="_blank">Camera</a> Hasselblad chuyên nghiệp thế hệ mới, nổi bật là camera tele 50MP Zoom Quang Học 10x đầu tiên trên thế giới.</p>

<p>Để hiện thực hóa bước tiến này, OPPO phát triển cấu trúc <a href="https://cellphones.com.vn/may-anh/phu-kien-may-anh/ong-kinh-lens.html" target="_blank">ống kính</a> tiềm vọng 5 lăng kính, không những cho phép mở rộng khả năng zoom quang học mà còn thu gọn 30% kích thước mô-đun, giữ trọn thiết kế mỏng nhẹ tinh tế. Nhờ sự hỗ trợ của công nghệ tinh khiết hóa ánh sáng và hệ thống chống rung cảm biến cao cấp, thiết bị mang đến trải nghiệm Zoom chất lượng quang học 20x với độ ổn định tuyệt đối và chi tiết sắc nét vượt trội.</p>

<p style="text-align:center"><img alt="" height="533" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-2.jpg" width="1200"></p>

<p>Bên cạnh camera tele Hasselblad 50MP zoom quang học 10x, Find X9 Ultra còn sở hữu hệ thống Camera kép Hasselblad 200MP, gồm camera chính sử dụng cảm biến Sony LYTIA 901 kích thước 1/1.12 inch, khẩu độ f/1.5, cùng Camera Tele Chân Dung Hasselblad 3x 200MP với cảm biến 1/1.28 inch và khẩu độ f/2.2, hỗ trợ tối ưu khả năng thu sáng.</p>

<p>Hệ thống được hoàn thiện với Camera Góc Siêu Rộng 50MP và camera Tái Tạo Màu Thế Hệ Mới, mang đến chất ảnh tự nhiên, chân thực hơn.</p>

<p>Tiếp nối dấu ấn hợp tác cùng Hasselblad, Find X9 Ultra còn đi kèm bộ ống kính tele OPPO Hasselblad Explorer, bao gồm ốp lưng OPPO Hasselblad Explorer tích hợp phím chụp và vòng xoay vật lý, cùng ống kính tele OPPO Hasselblad Explorer 300mm. Khi kết hợp với Camera Tele 3x, phụ kiện này mở rộng tiêu cự lên 300mm, tương đương zoom quang học 13x, đồng thời duy trì độ chi tiết cao ngay cả ở các mức zoom lớn hơn.</p>

<p style="text-align:center"><img alt="" height="800" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-3.jpg" width="1200"></p>

<p>Ngoài khả năng nhiếp ảnh, năng lực quay video cũng được OPPO nâng cấp hỗ trợ Quay Video 4K 60fps Dolby Vision, duy trì chất lượng zoom ổn định từ 0.6x đến 30x. Đặc biệt, hệ thống camera kép 200MP cho phép Quay Video 4K 120fps Dolby Vision và lần đầu tiên hỗ trợ Quay Video 8K Siêu Nét trên flagship OPPO.</p>

<p>Đối với các nhà sáng tạo chuyên nghiệp, sản phẩm giới thiệu O-Log2 giúp mở rộng dải tương phản và hỗ trợ hệ thống ACES, cùng khả năng tải 3D LUT trực tiếp để xem trước hoặc áp dụng profile màu thời gian thực qua tính năng LUT Burn-in.</p>

<div class="grid-cols-2 sforum-gallery">
<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-4.jpg"></div>

<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-5.jpg"></div>
</div>

<p>OPPO Find X9 Ultra được trang bị vi xử lý Qualcomm Snapdragon 8 Elite Gen 5, kết hợp hệ thống tản nhiệt buồng hơi và cụm tản nhiệt khép kín, giúp duy trì hiệu năng mượt mà, ổn định trong thời gian dài, kể cả với các tác vụ nặng như quay video 8K.</p>

<p>Thiết bị sở hữu viên pin Silicon-Carbon dung lượng 7050mAh, hỗ trợ Sạc Siêu Nhanh SUPERVOOC 100W và Sạc Không Dây Siêu Nhanh AIRVOOC 50W, mang đến trải nghiệm sử dụng bền bỉ hơn cho người dùng. Find X9 Ultra ra mắt với hai tùy chọn màu sắc gồm phiên bản Nâu lấy cảm hứng từ mẫu <a href="https://cellphones.com.vn/may-anh.html" target="_blank">máy ảnh</a> Hasselblad X2D và phiên bản Cam nổi bật, cá tính.</p>

<blockquote>
<p>Tham khảo các điện thoại OPPO chất lượng đang bán tại <a href="https://cellphones.com.vn/" target="_blank">CellphoneS</a>:</p>

<div class="sforum-insertbutton" style="width:100%">
<p style="text-align:center"><a class="sforum_cta_button sforum-insertbutton-btn" href="https://cellphones.com.vn/mobile/oppo.html" rel="external noopener noreferrer nofollow" target="_blank">Mua điện thoại OPPO giá tốt</a></p>
</div>
</blockquote>

<h2 id="oppo-find-x9s-nguoi-ban-dong-hanh-hasselblad-cua-nhung-chuyen-hanh-trinh-sang-tao-day-cam-hung" style="scroll-margin : 125px;"><strong>OPPO Find X9s: Người bạn đồng hành Hasselblad của những chuyến hành trình sáng tạo đầy cảm hứng</strong></h2>

<p>Được định vị là mẫu flagship mang trải nghiệm nhiếp ảnh Hasselblad đến gần hơn với người dùng trẻ, OPPO Find X9s tập trung vào tính di động, sự linh hoạt và khả năng ghi lại trọn vẹn không khí của mỗi chuyến đi. Thiết bị sở hữu bộ ba camera siêu nét 50MP bao gồm cảm biến chính 50MP tích hợp chống rung quang học OIS, mang lại những khung hình ấn tượng từ chân dung trong ánh hoàng hôn đến cảnh đêm thành phố thiếu sáng.</p>

<p style="text-align:center"><img alt="" height="533" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-9.jpg" width="1200"></p>

<p>Camera tele Hasselblad 50MP zoom quang học 3x, sử dụng cảm biến lớn 1/1,95 inch, mang đến khả năng zoom hàng đầu phân khúc cùng hiệu ứng nén phối cảnh tự nhiên, giúp tạo nên những bức chân dung có chiều sâu và chất ảnh rõ nét. Camera góc siêu rộng 50MP với góc nhìn 120° hỗ trợ ghi lại những khung cảnh rộng lớn một cách trọn vẹn, đáp ứng đa dạng nhu cầu từ chụp chân dung, phong cảnh đến những khung hình đời thường giàu cảm xúc.</p>

<p>Trên Find X9s, dấu ấn hợp tác cùng Hasselblad không chỉ hiện diện ở hệ thống camera mà còn được mở rộng thành một trải nghiệm hình ảnh trọn vẹn hơn. Chế độ Chân Dung Hasselblad mang đến những bức ảnh chân dung chất lượng cao với hiệu ứng xóa phông được AI hỗ trợ, giúp tách biệt chủ thể và hậu cảnh một cách tự nhiên, chính xác.</p>

<p style="text-align:center"><img alt="" height="800" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-10.jpg" width="1200"></p>

<p>Trong khi đó, Chế độ Bậc Thầy Hasselblad cho phép người dùng chủ động kiểm soát các thông số như tốc độ màn trập, ISO, lấy nét và cân bằng sáng, đi kèm 16 bộ lọc màu tùy chỉnh và khả năng lưu ảnh ở các định dạng chất lượng cao như RAW Max 16-bit và JPG Max, đồng thời tương thích với chuẩn hiển thị ProXDR.</p>

<p>Với nhu cầu ghi lại những khoảnh khắc chuyển động, tính năng Chụp Nhanh Siêu Nét hỗ trợ chụp liên tiếp tối đa 200 khung hình chỉ bằng thao tác nhấn giữ nút chụp, kết hợp cơ chế màn trập không độ trễ và thuật toán nhận diện chủ thể theo thời gian thực để giảm thiểu hiện tượng nhòe mờ và duy trì chất lượng hình ảnh.</p>

<p style="text-align:center"><img alt="" height="533" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-9.jpg" width="1200"></p>

<p>Bên cạnh đó, toàn bộ hệ thống camera trên Find X9s đều hỗ trợ quay video 4K 60fps với Dolby Vision HDR, mang đến màu sắc sống động và chi tiết rõ nét, qua đó giúp người dùng tiếp cận gần hơn với một trải nghiệm nhiếp ảnh di động mang tính cá nhân, linh hoạt và giàu cảm hứng.</p>

<div class="grid-cols-2 sforum-gallery">
<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-11.jpg"></div>

<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-12.jpg"></div>
</div>

<p>Mang tinh thần phóng khoáng của những chuyến đi, Find X9s được hoàn thiện với thân máy mỏng 7.99mm cùng ba tùy chọn màu sắc thanh lịch: Xám, Cam Nhạt và Tím Nhạt. Máy sở hữu <a href="https://cellphones.com.vn/man-hinh.html" target="_blank">màn hình</a> phẳng 6.59 inch, độ sáng tối đa 3,600 nits và viền mỏng 1.15mm, mang lại trải nghiệm hiển thị rõ ràng trong nhiều điều kiện ánh sáng khác nhau, từ phố cổ lúc nắng gắt đến những khung cảnh về đêm.</p>

<p>Nhằm đáp ứng nhu cầu di chuyển, máy được trang bị các tiêu chuẩn kháng nước, kháng bụi IP66, IP68, IP69 và đạt chứng nhận chống va đập 5 sao từ tổ chức SGS (Thụy Sĩ). Thiết bị sử dụng vi xử lý MediaTek Dimensity 9500s tiến trình 3nm, kết hợp hệ thống tản nhiệt buồng hơi và công nghệ phân bổ tài nguyên Trinity Engine, đảm bảo thiết bị luôn vận hành mượt mà, tối ưu hóa điện năng từ tác vụ quay 4K đến giải trí cường độ cao.</p>

<p style="text-align:center"><img alt="" height="675" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-13.jpg" width="1200"></p>

<p>OPPO Find X9s được trang bị viên pin Silicon-Carbon dung lượng 7,025mAh, hỗ trợ sạc nhanh có dây 80W SUPERVOOC và được thiết kế để duy trì trên 80% dung lượng sau 5 năm sử dụng.&nbsp;</p>

<p>Vận hành trên nền tảng ColorOS, OPPO Find X9s được trang bị loạt tính năng AI phục vụ trực tiếp cho nhu cầu thực tế của người dùng, giúp mỗi chuyến đi trở nên thuận tiện và linh hoạt hơn. Để giải quyết rào cản ngôn ngữ, Dịch Thực Đơn AI cho phép quét và chuyển ngữ tức thì các món ăn quốc tế, đồng thời cung cấp hình ảnh trực quan, tự động quy đổi tỷ giá và cảnh báo thành phần dễ gây dị ứng.</p>

<p style="text-align:center"><img alt="" height="675" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/OPPO-Find-X9s-Find-X9-ultra-ra-mat-vn-14.jpg" width="1200"></p>

<p>Đồng hành cùng người dùng là Trợ Lý Ghi Nhớ AI hoạt động dựa trên hệ thống đa mô hình, sẵn sàng đáp ứng và phản hồi thông tin theo nhu cầu cá nhân hóa. Hơn thế nữa, việc theo dõi ngân sách du lịch trở nên tối giản hơn bao giờ hết với tính năng Quản Lý Hóa Đơn AI trên AI Mindspace. Bằng cách số hóa hóa đơn giấy và thu thập hóa đơn điện tử, AI sẽ thay bạn tính toán, quy đổi ngoại tệ và đưa ra những gợi ý chi tiêu thông minh.</p>

<p>Với việc tích hợp hàng loạt công nghệ đột phá về camera và giải pháp AI thực tiễn, bộ đôi Find X9 Ultra và Find X9s hứa hẹn sẽ thiết lập những tiêu chuẩn mới, mang lại trải nghiệm công nghệ toàn diện và tối ưu cho người dùng trong thời gian tới.</p>

<h2 id="gia-ban-hap-dan" style="scroll-margin : 125px;"><strong>Giá bán hấp dẫn</strong></h2>

<p>Bộ đôi OPPO Find X9s và Find X9 Ultra sẽ được mở bán tại thị trường Việt Nam với giá bán từng phiên bản như sau:</p>

<ul>
	<li>OPPO Find X9s 12GB/256GB: 24,990,000đ</li>
	<li>OPPO Find X9s 12GB/512GB: 26,990,000đ</li>
	<li>OPPO Find X9 Ultra 12GB/512GB: 49,990,000đ</li>
</ul>

<p>Hiện tại, bạn có thể đặt trước các siêu phẩm mới đến từ nhà OPPO bằng cách truy cập vào danh sách bên dưới:</p>

