INSERT INTO public.products VALUES (23, 2, 'iPhone 17 Pro Max', 'iphone-17-pro-max-69fae13bf029d', 'Apple', 'iPhone 17 Pro Max là mẫu flagship cao cấp với thiết kế sang trọng, màn hình lớn sắc nét cùng hiệu năng mạnh mẽ. Máy nổi bật với camera cải tiến cho chất lượng chụp ảnh vượt trội, thời lượng pin bền bỉ và trải nghiệm mượt mà, đáp ứng tốt cả công việc lẫn giải trí.', '/storage/products/fzExfB2GC1E4e2X2yyOr9DFHkqI7hks5kCt7ge94.jpg', true, '2026-05-05 23:35:39+00', '2026-05-05 23:50:54+00', NULL, '<div id="cpsContent" class="cps-block-content" style="max-height: 100000px;"><h2 class="ksp-title">
    Đặc điểm nổi bật của iPhone 17 Pro Max 256GB | Chính hãng
  </h2> <div class="ksp-content" style=""><blockquote>
<p style="text-align: justify;"><strong>iPhone 17 Pro Max</strong> là mẫu chiếc <strong>smartphone cao cấp nhất của Apple ra mắt năm 2025,</strong> nổi bật với khung nhôm rèn nhiệt siêu nhẹ, <strong>chip A19 Pro</strong> mạnh mẽ, và <strong>camera 48MP</strong> thuộc dòng <a href="https://cellphones.com.vn/mobile/apple/iphone-17.html" title="iPhone 17 series" target="_blank"><strong>iPhone 17 series</strong></a> của Apple. Thiết bị <strong>iPhone 17 Pro Max được coi là "vũ khí chiến lược" của thế hệ iPhone mới</strong> còn được tích hợp nhiều công nghệ mới nhằm tối ưu khả năng hiển thị, chụp ảnh và <strong>thời lượng sử dụng pin lên đến 37 giờ</strong> đáp ứng cho nhu cầu làm việc và giải trí.</p>
</blockquote>
<p style="text-align: justify;"><img provider="CPS_IMG_PROVIDER" format="webp" loading="lazy" alt="hình ảnh iPhone 17 Pro Max" src="https://cdn2.cellphones.com.vn/insecure/rs:fill:0:0/q:100/plain/https://cellphones.com.vn/media/wysiwyg/Phone/Apple/iPhone-17/iphone-17-pro-max-6.jpg" title="hình ảnh iPhone 17 Pro Max"></p>
