INSERT INTO public.notifications VALUES (1, 3, 'order_confirmed', 'Đơn hàng đã được xác nhận', 'Đơn hàng OD-SEED-0001 đang được xử lý.', '{"orderCode": "OD-SEED-0001"}', NULL, '2026-04-29 08:03:10.923461+00', '2026-04-29 08:03:10.923461+00');
INSERT INTO public.notifications VALUES (6, 10, 'order_return_request', 'Yêu cầu hoàn trả mới', 'Đơn #OD-KEUFXEPMXC vừa có yêu cầu hoàn trả.', '{"order_id": 2, "order_code": "OD-KEUFXEPMXC"}', '2026-05-07 01:18:43+00', '2026-05-07 01:17:41+00', '2026-05-07 01:18:43+00');
INSERT INTO public.notifications VALUES (8, 11, 'order_return_approved', 'Yêu cầu hoàn trả đã được phê duyệt', 'Admin đã phê duyệt yêu cầu hoàn trả cho đơn #OD-KEUFXEPMXC.', '{"order_id": 2, "order_code": "OD-KEUFXEPMXC", "return_request_status": "approved"}', '2026-05-07 01:19:35+00', '2026-05-07 01:19:19+00', '2026-05-07 01:19:35+00');
INSERT INTO public.notifications VALUES (9, 11, 'order_return_refunded', 'Đơn hàng đã được hoàn tiền', 'Admin đã hoàn tiền cho yêu cầu hoàn trả của đơn #OD-KEUFXEPMXC.', '{"order_id": 2, "admin_note": "Xin chào  Đỗ Việt Hoàng,\r\n\r\nE-TECH MARKET đã tiếp nhận yêu cầu hoàn trả cho sản phẩm iPhone 14 Pro 128GB với mã đơn hàng #OD-KEUFXEPMXC.\r\n\r\nSau khi kiểm tra thông tin mà quý khách cung cấp, chúng tôi xác nhận yêu cầu hoàn tiền đang được xử lý. Bộ phận kỹ thuật sẽ tiến hành kiểm tra tình trạng thiết bị sau khi nhận sản phẩm thực tế để đảm bảo đủ điều kiện áp dụng chính sách hoàn trả.\r\n\r\nThông tin hoàn tiền:\r\n\r\n* Ngân hàng: MB Bank\r\n* Số tài khoản: 0987654321\r\n* Chủ tài khoản: NGUYEN VAN A\r\n\r\nThời gian xử lý hoàn tiền dự kiến từ 3 – 7 ngày làm việc kể từ khi xác nhận sản phẩm hợp lệ.\r\n\r\nVui lòng đóng gói đầy đủ sản phẩm, phụ kiện và gửi hàng về trung tâm tiếp nhận bảo hành/hoàn trả của E-TECH MARKET.\r\n\r\nCảm ơn quý khách đã sử dụng dịch vụ của chúng tôi.", "order_code": "OD-KEUFXEPMXC", "refund_proof": [{"url": "/storage/returns/2/refund-proof/Ob4ab3bdTIOgGKgOo36BW1OdJU1EQtwqDAjlL73F.png", "mime": "image/png", "size": 239803, "type": "image", "original_name": "b_c_1_1.png"}], "return_request_status": "refunded"}', '2026-05-07 01:19:57+00', '2026-05-07 01:19:52+00', '2026-05-07 01:19:57+00');
INSERT INTO public.notifications VALUES (10, 10, 'order_refund_confirmed', 'Khách đã xác nhận nhận tiền hoàn', 'Đơn #OD-KEUFXEPMXC đã được khách xác nhận nhận tiền hoàn.', '{"order_id": 2, "order_code": "OD-KEUFXEPMXC"}', '2026-05-07 01:20:14+00', '2026-05-07 01:20:07+00', '2026-05-07 01:20:14+00');
