INSERT INTO public.product_faqs VALUES (1, 9, 'iPhone 14 Pro xem video được bao lâu? Có hỗ trợ sạc nhanh không?', 'iPhone 14 Pro được trang bị viên pin cho thời lượng sử dụng lên tới 23 giờ, thời lượng sử dụng đủ dài để bạn có thể sử dụng thoải mái mà không lo hết pin. Ngoài ra, máy cũng hỗ trợ sạc nhanh 20W, nhờ vậy máy có thể sạc tới 50% trong khoảng 30 phút.', 0, true, '2026-05-04 08:16:14', '2026-05-04 08:35:39', '2026-05-04 08:35:39');
INSERT INTO public.product_faqs VALUES (2, 9, 'Hiệu năng iPhone 14 Pro được cải tiến ra sao?', 'iPhone 14 Pro trang bị con chip xử lí được xây dựng trên tiến trình 4 nanomet mang lại hiệu năng cũng như hiệu suất cao, sử dụng ít năng lượng hơn 20% so với A15 Bionic, nhờ đó bạn hoàn toàn có thể tự tin chiến mọi game đồ họa khủng không lo giật lag.', 1, true, '2026-05-04 08:16:14', '2026-05-04 08:35:39', '2026-05-04 08:35:39');
INSERT INTO public.product_faqs VALUES (3, 9, 'Camera iPhone 14 Pro có đáp ứng được nhu cầu chụp ảnh chuyên nghiệp không?', 'Hoàn toàn có khả năng. Camera chính của iPhone 14 Pro có cảm biến lớn hơn 65% so với thế hệ tiền nhiệm và độ phân giải là 48 MP. Máy sở hữu nhiều tính năng cải tiến như Action Mode, ProRAW và quay Cinematic Mode lên tới độ phân giải 4K. Bên cạnh đó, khả năng cân bằng trắng và lấy nét cải thiện đáng kể cũng như những nâng cấp đáng giá về khả năng chụp đêm chắc chắn sẽ đem lại những khung hình chuyên nghiệp chuẩn điện ảnh.', 2, true, '2026-05-04 08:16:14', '2026-05-04 08:35:39', '2026-05-04 08:35:39');
INSERT INTO public.product_faqs VALUES (4, 9, 'Dynamic Island trên iPhone 14 Pro có tác dụng gì? Hoạt động như thế nào?', 'Dynamic Island là phần cắt hình viên thuốc mới trên iPhone 14 Pro và iPhone 14 Pro Max. Bên cạnh làm ngoại hình iPhone đẹp hơn, nó còn có thể hoạt động song song với các ứng dụng khác, biến đổi thành nhiều hình dạng để hiển thị các thông tin khác nhau.', 3, true, '2026-05-04 08:16:14', '2026-05-04 08:35:39', '2026-05-04 08:35:39');
INSERT INTO public.product_faqs VALUES (5, 9, 'iPhone 14 Pro có mấy màu, có những phiên bản bộ nhớ nào?', 'iPhone 14 Pro bao gồm 4 sắc màu thời thượng và hiện đại là: Đen (Space Black), Bạc (Silver), Vàng (Gold), Tím đậm (Deep Purple). Dòng iPhone này bao gồm 4 phiên bản bộ nhớ 128GB, 256Gb, 512GB và 1TB đa dạng, giúp bạn có thêm nhiều lựa chọn.', 4, true, '2026-05-04 08:16:14', '2026-05-04 08:35:39', '2026-05-04 08:35:39');
INSERT INTO public.product_faqs VALUES (6, 9, 'iPhone 14 Pro xem video được bao lâu? Có hỗ trợ sạc nhanh không?', 'iPhone 14 Pro được trang bị viên pin cho thời lượng sử dụng lên tới 23 giờ, thời lượng sử dụng đủ dài để bạn có thể sử dụng thoải mái mà không lo hết pin. Ngoài ra, máy cũng hỗ trợ sạc nhanh 20W, nhờ vậy máy có thể sạc tới 50% trong khoảng 30 phút.', 0, true, '2026-05-04 08:35:39', '2026-05-04 08:36:34', '2026-05-04 08:36:34');
