INSERT INTO public.product_faqs VALUES (137, 23, 'iPhone 17 Pro Max có mấy màu?', 'iPhone 17 Pro Max có 3 tùy chọn màu sắc bao gồm: Cam Vũ Trụ, Bạc và Xanh Đậm.', 4, true, '2026-05-06 06:49:49', '2026-05-06 06:50:34', '2026-05-06 06:50:34');
INSERT INTO public.product_faqs VALUES (259, 40, 'Bosch SMS8YCI01E rửa được bao nhiêu bộ?', 'Máy có sức chứa lên đến 14 bộ chén đĩa.', 0, true, '2026-05-12 14:33:02', '2026-05-12 14:33:02', NULL);
INSERT INTO public.product_faqs VALUES (260, 40, 'Máy có tiết kiệm nước không?', 'Có, chỉ tiêu thụ khoảng 9.5 lít/lần rửa.', 1, true, '2026-05-12 14:33:02', '2026-05-12 14:33:02', NULL);
INSERT INTO public.product_faqs VALUES (261, 40, 'Máy có diệt khuẩn không?', 'Có, hỗ trợ công nghệ Hygiene Plus.', 2, true, '2026-05-12 14:33:02', '2026-05-12 14:33:02', NULL);
INSERT INTO public.product_faqs VALUES (262, 40, 'Máy có điều khiển bằng điện thoại không?', 'Có, hỗ trợ Home Connect.', 3, true, '2026-05-12 14:33:02', '2026-05-12 14:33:02', NULL);
INSERT INTO public.product_faqs VALUES (263, 40, 'Máy có sấy khô không?', 'Có, sử dụng công nghệ Zeolith và Extra Dry.', 4, true, '2026-05-12 14:33:02', '2026-05-12 14:33:02', NULL);
INSERT INTO public.product_faqs VALUES (264, 40, 'Máy có chống rò rỉ nước không?', 'Có, trang bị hệ thống AquaStop an toàn.', 5, true, '2026-05-12 14:33:02', '2026-05-12 14:33:02', NULL);
INSERT INTO public.product_faqs VALUES (325, 51, 'Bàn chải Philips HX4031/21 dùng công nghệ gì?', 'Sử dụng công nghệ sóng âm Sonic.', 0, true, '2026-05-12 16:07:20', '2026-05-13 16:37:09', '2026-05-13 16:37:09');
INSERT INTO public.product_faqs VALUES (326, 51, 'Có bao nhiêu chế độ chải?', 'Có 3 chế độ làm sạch.', 1, true, '2026-05-12 16:07:20', '2026-05-13 16:37:09', '2026-05-13 16:37:09');
INSERT INTO public.product_faqs VALUES (327, 51, 'Pin dùng được bao lâu?', 'Khoảng 14 ngày.', 2, true, '2026-05-12 16:07:20', '2026-05-13 16:37:09', '2026-05-13 16:37:09');
INSERT INTO public.product_faqs VALUES (328, 51, 'Có nhắc thời gian chải không?', 'Có, nhắc mỗi 30 giây và đủ 2 phút.', 3, true, '2026-05-12 16:07:20', '2026-05-13 16:37:09', '2026-05-13 16:37:09');
