INSERT INTO public.product_faqs VALUES (18, 9, 'Camera iPhone 14 Pro có đáp ứng được nhu cầu chụp ảnh chuyên nghiệp không?', 'Hoàn toàn có khả năng. Camera chính của iPhone 14 Pro có cảm biến lớn hơn 65% so với thế hệ tiền nhiệm và độ phân giải là 48 MP. Máy sở hữu nhiều tính năng cải tiến như Action Mode, ProRAW và quay Cinematic Mode lên tới độ phân giải 4K. Bên cạnh đó, khả năng cân bằng trắng và lấy nét cải thiện đáng kể cũng như những nâng cấp đáng giá về khả năng chụp đêm chắc chắn sẽ đem lại những khung hình chuyên nghiệp chuẩn điện ảnh.', 2, true, '2026-05-04 08:37:02', '2026-05-04 08:58:34', '2026-05-04 08:58:34');
INSERT INTO public.product_faqs VALUES (19, 9, 'Dynamic Island trên iPhone 14 Pro có tác dụng gì? Hoạt động như thế nào?', 'Dynamic Island là phần cắt hình viên thuốc mới trên iPhone 14 Pro và iPhone 14 Pro Max. Bên cạnh làm ngoại hình iPhone đẹp hơn, nó còn có thể hoạt động song song với các ứng dụng khác, biến đổi thành nhiều hình dạng để hiển thị các thông tin khác nhau.', 3, true, '2026-05-04 08:37:02', '2026-05-04 08:58:34', '2026-05-04 08:58:34');
INSERT INTO public.product_faqs VALUES (20, 9, 'iPhone 14 Pro có mấy màu, có những phiên bản bộ nhớ nào?', 'iPhone 14 Pro bao gồm 4 sắc màu thời thượng và hiện đại là: Đen (Space Black), Bạc (Silver), Vàng (Gold), Tím đậm (Deep Purple). Dòng iPhone này bao gồm 4 phiên bản bộ nhớ 128GB, 256Gb, 512GB và 1TB đa dạng, giúp bạn có thêm nhiều lựa chọn.', 4, true, '2026-05-04 08:37:02', '2026-05-04 08:58:34', '2026-05-04 08:58:34');
INSERT INTO public.product_faqs VALUES (133, 23, 'iPhone 17 Pro Max sạc nhanh bao nhiêu W?', 'Theo thông tin từ Apple, iPhone 17 Pro Max hỗ trợ sạc nhanh lên đến 50% trong 20 phút với bộ tiếp hợp 40W trở lên.', 0, true, '2026-05-06 06:49:49', '2026-05-06 06:50:34', '2026-05-06 06:50:34');
