INSERT INTO public.product_faqs VALUES (135, 23, 'iPhone 17 Pro Max pin bao nhiêu?', 'Mặc dù không đề cập đến dung lượng pin cụ thể, nhưng Apple cũng đã công bố thời gian xem video trên iPhone 17 Pro Max có thể lên đến 37 giờ, dài hơn đến 8 giờ so với iPhone 15 Pro Max.', 2, true, '2026-05-06 06:49:49', '2026-05-06 06:50:34', '2026-05-06 06:50:34');
INSERT INTO public.product_faqs VALUES (136, 23, 'iPhone 17 Pro Max bao nhiêu inch?', 'iPhone 17 Pro Max được trang bị màn hình Super Retina XDR kích thước 6.9 inch với thiết kế viền siêu mỏng.', 3, true, '2026-05-06 06:49:49', '2026-05-06 06:50:34', '2026-05-06 06:50:34');
