INSERT INTO public.product_faqs VALUES (36, 9, 'iPhone 14 Pro xem video được bao lâu? Có hỗ trợ sạc nhanh không?', 'iPhone 14 Pro được trang bị viên pin cho thời lượng sử dụng lên tới 23 giờ, thời lượng sử dụng đủ dài để bạn có thể sử dụng thoải mái mà không lo hết pin. Ngoài ra, máy cũng hỗ trợ sạc nhanh 20W, nhờ vậy máy có thể sạc tới 50% trong khoảng 30 phút.', 0, true, '2026-05-04 09:06:24', '2026-05-04 09:07:13', '2026-05-04 09:07:13');
INSERT INTO public.product_faqs VALUES (37, 9, 'Hiệu năng iPhone 14 Pro được cải tiến ra sao?', 'iPhone 14 Pro trang bị con chip xử lí được xây dựng trên tiến trình 4 nanomet mang lại hiệu năng cũng như hiệu suất cao, sử dụng ít năng lượng hơn 20% so với A15 Bionic, nhờ đó bạn hoàn toàn có thể tự tin chiến mọi game đồ họa khủng không lo giật lag.', 1, true, '2026-05-04 09:06:24', '2026-05-04 09:07:13', '2026-05-04 09:07:13');
INSERT INTO public.product_faqs VALUES (38, 9, 'Camera iPhone 14 Pro có đáp ứng được nhu cầu chụp ảnh chuyên nghiệp không?', 'Hoàn toàn có khả năng. Camera chính của iPhone 14 Pro có cảm biến lớn hơn 65% so với thế hệ tiền nhiệm và độ phân giải là 48 MP. Máy sở hữu nhiều tính năng cải tiến như Action Mode, ProRAW và quay Cinematic Mode lên tới độ phân giải 4K. Bên cạnh đó, khả năng cân bằng trắng và lấy nét cải thiện đáng kể cũng như những nâng cấp đáng giá về khả năng chụp đêm chắc chắn sẽ đem lại những khung hình chuyên nghiệp chuẩn điện ảnh.', 2, true, '2026-05-04 09:06:24', '2026-05-04 09:07:13', '2026-05-04 09:07:13');
