INSERT INTO public.product_faqs VALUES (54, 9, 'Dynamic Island trên iPhone 14 Pro có tác dụng gì? Hoạt động như thế nào?', 'Dynamic Island là phần cắt hình viên thuốc mới trên iPhone 14 Pro và iPhone 14 Pro Max. Bên cạnh làm ngoại hình iPhone đẹp hơn, nó còn có thể hoạt động song song với các ứng dụng khác, biến đổi thành nhiều hình dạng để hiển thị các thông tin khác nhau.', 3, true, '2026-05-05 01:12:42', '2026-05-05 01:49:58', '2026-05-05 01:49:58');
INSERT INTO public.product_faqs VALUES (55, 9, 'iPhone 14 Pro có mấy màu, có những phiên bản bộ nhớ nào?', 'iPhone 14 Pro bao gồm 4 sắc màu thời thượng và hiện đại là: Đen (Space Black), Bạc (Silver), Vàng (Gold), Tím đậm (Deep Purple). Dòng iPhone này bao gồm 4 phiên bản bộ nhớ 128GB, 256Gb, 512GB và 1TB đa dạng, giúp bạn có thêm nhiều lựa chọn.', 4, true, '2026-05-05 01:12:42', '2026-05-05 01:49:58', '2026-05-05 01:49:58');
INSERT INTO public.product_faqs VALUES (56, 9, 'iPhone 14 Pro xem video được bao lâu? Có hỗ trợ sạc nhanh không?', 'iPhone 14 Pro được trang bị viên pin cho thời lượng sử dụng lên tới 23 giờ, thời lượng sử dụng đủ dài để bạn có thể sử dụng thoải mái mà không lo hết pin. Ngoài ra, máy cũng hỗ trợ sạc nhanh 20W, nhờ vậy máy có thể sạc tới 50% trong khoảng 30 phút.', 0, true, '2026-05-05 01:49:58', '2026-05-05 02:00:08', '2026-05-05 02:00:08');
