INSERT INTO public.product_faqs VALUES (93, 9, 'Camera iPhone 14 Pro có đáp ứng được nhu cầu chụp ảnh chuyên nghiệp không?', 'Hoàn toàn có khả năng. Camera chính của iPhone 14 Pro có cảm biến lớn hơn 65% so với thế hệ tiền nhiệm và độ phân giải là 48 MP. Máy sở hữu nhiều tính năng cải tiến như Action Mode, ProRAW và quay Cinematic Mode lên tới độ phân giải 4K. Bên cạnh đó, khả năng cân bằng trắng và lấy nét cải thiện đáng kể cũng như những nâng cấp đáng giá về khả năng chụp đêm chắc chắn sẽ đem lại những khung hình chuyên nghiệp chuẩn điện ảnh.', 2, true, '2026-05-05 02:58:20', '2026-05-05 02:58:55', '2026-05-05 02:58:55');
