INSERT INTO public.product_faqs VALUES (113, 9, 'Camera iPhone 14 Pro có đáp ứng được nhu cầu chụp ảnh chuyên nghiệp không?', 'Hoàn toàn có khả năng. Camera chính của iPhone 14 Pro có cảm biến lớn hơn 65% so với thế hệ tiền nhiệm và độ phân giải là 48 MP. Máy sở hữu nhiều tính năng cải tiến như Action Mode, ProRAW và quay Cinematic Mode lên tới độ phân giải 4K. Bên cạnh đó, khả năng cân bằng trắng và lấy nét cải thiện đáng kể cũng như những nâng cấp đáng giá về khả năng chụp đêm chắc chắn sẽ đem lại những khung hình chuyên nghiệp chuẩn điện ảnh.', 2, true, '2026-05-05 03:41:54', '2026-05-05 03:41:54', NULL);
INSERT INTO public.product_faqs VALUES (114, 9, 'Dynamic Island trên iPhone 14 Pro có tác dụng gì? Hoạt động như thế nào?', 'Dynamic Island là phần cắt hình viên thuốc mới trên iPhone 14 Pro và iPhone 14 Pro Max. Bên cạnh làm ngoại hình iPhone đẹp hơn, nó còn có thể hoạt động song song với các ứng dụng khác, biến đổi thành nhiều hình dạng để hiển thị các thông tin khác nhau.', 3, true, '2026-05-05 03:41:54', '2026-05-05 03:41:54', NULL);
INSERT INTO public.product_faqs VALUES (115, 9, 'iPhone 14 Pro có mấy màu, có những phiên bản bộ nhớ nào?', 'iPhone 14 Pro bao gồm 4 sắc màu thời thượng và hiện đại là: Đen (Space Black), Bạc (Silver), Vàng (Gold), Tím đậm (Deep Purple). Dòng iPhone này bao gồm 4 phiên bản bộ nhớ 128GB, 256Gb, 512GB và 1TB đa dạng, giúp bạn có thêm nhiều lựa chọn.', 4, true, '2026-05-05 03:41:54', '2026-05-05 03:41:54', NULL);
INSERT INTO public.product_faqs VALUES (116, 13, 'AirPods 4 và AirPods 4 ANC khác nhau gì?', 'Phiên bản ANC có thêm chống ồn chủ động, xuyên âm và Adaptive Audio, còn bản thường thì không có các tính năng này.', 0, true, '2026-05-05 06:57:53', '2026-05-05 06:57:53', NULL);
INSERT INTO public.product_faqs VALUES (117, 13, 'AirPods 4 có dùng được với Android không?', 'Có. Cả hai phiên bản đều kết nối qua Bluetooth nên dùng được với Android, nhưng một số tính năng như Spatial Audio hoặc Siri sẽ bị hạn chế.', 1, true, '2026-05-05 06:57:53', '2026-05-05 06:57:53', NULL);
INSERT INTO public.product_faqs VALUES (118, 13, 'hời lượng pin của AirPods 4 là bao lâu?', 'Khoảng 5 giờ nghe nhạc cho mỗi lần sạc và lên đến 30 giờ khi dùng kèm hộp sạc (áp dụng cho cả 2 phiên bản).', 2, true, '2026-05-05 06:57:53', '2026-05-05 06:57:53', NULL);
INSERT INTO public.product_faqs VALUES (119, 13, 'AirPods 4 có chống nước không?', 'Có. Cả hai đều đạt chuẩn IP54, giúp chống bụi và chống nước nhẹ (mồ hôi, mưa nhỏ), nhưng không nên dùng khi bơi.', 3, true, '2026-05-05 06:57:53', '2026-05-05 06:57:53', NULL);
INSERT INTO public.product_faqs VALUES (120, 13, 'Có nên mua AirPods 4 ANC không?', 'Nếu bạn thường xuyên ở môi trường ồn (cafe, xe bus, văn phòng đông người) thì nên chọn bản ANC.
Nếu chỉ nghe nhạc cơ bản, tiết kiệm chi phí thì bản thường là đủ.', 4, true, '2026-05-05 06:57:53', '2026-05-05 06:57:53', NULL);
INSERT INTO public.product_faqs VALUES (121, 10, 'Redmi Note 15 có hỗ trợ 5G không?', 'Có, máy hỗ trợ kết nối 5G giúp truy cập internet tốc độ cao.', 1, true, '2026-05-05 09:07:09', '2026-05-05 09:07:09', NULL);
INSERT INTO public.product_faqs VALUES (122, 10, 'Pin Redmi Note 15 dùng được bao lâu?', 'Với dung lượng 5000mAh, máy có thể sử dụng thoải mái 1 ngày với nhu cầu thông thường.', 2, true, '2026-05-05 09:07:09', '2026-05-05 09:07:09', NULL);
INSERT INTO public.product_faqs VALUES (141, 23, 'iPhone 17 Pro Max bao nhiêu inch?', 'iPhone 17 Pro Max được trang bị màn hình Super Retina XDR kích thước 6.9 inch với thiết kế viền siêu mỏng.', 3, true, '2026-05-06 06:50:34', '2026-05-06 06:50:54', '2026-05-06 06:50:54');
INSERT INTO public.product_faqs VALUES (143, 23, 'iPhone 17 Pro Max sạc nhanh bao nhiêu W?', 'Theo thông tin từ Apple, iPhone 17 Pro Max hỗ trợ sạc nhanh lên đến 50% trong 20 phút với bộ tiếp hợp 40W trở lên.', 0, true, '2026-05-06 06:50:54', '2026-05-06 06:50:54', NULL);
INSERT INTO public.product_faqs VALUES (159, 7, 'ASUS TUF Gaming F15 (2023) có nâng cấp RAM và SSD được không?', 'Có. Máy hỗ trợ nâng cấp tối đa 64GB RAM với 2 khe SO-DIMM và hỗ trợ 2 khe SSD M.2 PCIe Gen 4 giúp mở rộng dung lượng dễ dàng.', 0, true, '2026-05-11 15:58:34', '2026-05-11 15:58:34', NULL);
INSERT INTO public.product_faqs VALUES (160, 7, 'ASUS TUF Gaming F15 (2023) chơi được những game nào?', 'Laptop có thể chơi tốt Valorant, CS2, GTA V, PUBG, Cyberpunk 2077 và nhiều tựa game AAA khác ở mức thiết lập High/Ultra Full HD.', 1, true, '2026-05-11 15:58:34', '2026-05-11 15:58:34', NULL);
INSERT INTO public.product_faqs VALUES (161, 7, 'ASUS TUF Gaming F15 (2023) có phù hợp cho học tập và làm việc không?', 'Có. Máy phù hợp cho lập trình, thiết kế đồ họa, chỉnh sửa video, render và đa nhiệm nhờ CPU Intel Core hiệu năng cao cùng GPU RTX mạnh mẽ.', 2, true, '2026-05-11 15:58:34', '2026-05-11 15:58:34', NULL);
INSERT INTO public.product_faqs VALUES (162, 7, 'ASUS TUF Gaming F15 (2023) có bị nóng khi chơi game lâu không?', 'Máy được trang bị hệ thống tản nhiệt Arc Flow Fans™, nhiều ống đồng và khe thoát nhiệt giúp duy trì nhiệt độ ổn định khi sử dụng hiệu năng cao.', 3, true, '2026-05-11 15:58:34', '2026-05-11 15:58:34', NULL);
INSERT INTO public.product_faqs VALUES (163, 7, 'ASUS TUF Gaming F15 (2023) có hỗ trợ công nghệ gaming hiện đại không?', 'Có. Máy hỗ trợ DLSS 3, Ray Tracing, MUX Switch, NVIDIA Advanced Optimus và màn hình tần số quét cao 144Hz/165Hz cho trải nghiệm gaming mượt mà.', 4, true, '2026-05-11 15:58:34', '2026-05-11 15:58:34', NULL);
INSERT INTO public.product_faqs VALUES (154, 26, 'Chuột Logitech MX Master 4 có hỗ trợ kết nối nhiều thiết bị không?', 'Có, MX Master 4 hỗ trợ kết nối cùng lúc tối đa 3 thiết bị thông qua Bluetooth hoặc USB Receiver và có thể chuyển đổi nhanh bằng nút Easy-Switch.', 0, true, '2026-05-08 09:43:24', '2026-05-12 09:49:50', '2026-05-12 09:49:50');
INSERT INTO public.product_faqs VALUES (155, 26, 'Pin của Logitech MX Master 4 sử dụng được bao lâu?', 'Chuột có thời lượng pin lên đến 70 ngày sau mỗi lần sạc đầy và chỉ cần sạc nhanh 1 phút để sử dụng khoảng 3 giờ.', 1, true, '2026-05-08 09:43:24', '2026-05-12 09:49:50', '2026-05-12 09:49:50');
INSERT INTO public.product_faqs VALUES (156, 26, 'MX Master 4 for Mac có dùng được cho Windows không?', 'Phiên bản MX Master 4 for Mac được tối ưu cho macOS và iPadOS, tuy nhiên vẫn có thể kết nối với một số thiết bị khác hỗ trợ Bluetooth.', 2, true, '2026-05-08 09:43:24', '2026-05-12 09:49:50', '2026-05-12 09:49:50');
INSERT INTO public.product_faqs VALUES (157, 26, 'Chuột Logitech MX Master 4 có phù hợp cho công việc thiết kế và lập trình không?', 'Có, với cảm biến Darkfield 8000 DPI, bánh xe cuộn MagSpeed và thiết kế công thái học, sản phẩm rất phù hợp cho lập trình viên, designer và dân văn phòng chuyên nghiệp.', 3, true, '2026-05-08 09:43:24', '2026-05-12 09:49:50', '2026-05-12 09:49:50');
INSERT INTO public.product_faqs VALUES (158, 26, 'MX Master 4 có cần cài phần mềm để sử dụng đầy đủ tính năng không?', 'Người dùng nên cài đặt Logi Options+ để tùy chỉnh nút bấm, tạo shortcut và tối ưu trải nghiệm sử dụng trên từng ứng dụng.', 4, true, '2026-05-08 09:43:24', '2026-05-12 09:49:50', '2026-05-12 09:49:50');
INSERT INTO public.product_faqs VALUES (164, 26, 'Chuột Logitech MX Master 4 có hỗ trợ kết nối nhiều thiết bị không?', 'Có, MX Master 4 hỗ trợ kết nối cùng lúc tối đa 3 thiết bị thông qua Bluetooth hoặc USB Receiver và có thể chuyển đổi nhanh bằng nút Easy-Switch.', 0, true, '2026-05-12 09:49:50', '2026-05-12 09:49:50', NULL);
INSERT INTO public.product_faqs VALUES (165, 26, 'Pin của Logitech MX Master 4 sử dụng được bao lâu?', 'Chuột có thời lượng pin lên đến 70 ngày sau mỗi lần sạc đầy và chỉ cần sạc nhanh 1 phút để sử dụng khoảng 3 giờ.', 1, true, '2026-05-12 09:49:50', '2026-05-12 09:49:50', NULL);
INSERT INTO public.product_faqs VALUES (166, 26, 'MX Master 4 for Mac có dùng được cho Windows không?', 'Phiên bản MX Master 4 for Mac được tối ưu cho macOS và iPadOS, tuy nhiên vẫn có thể kết nối với một số thiết bị khác hỗ trợ Bluetooth.', 2, true, '2026-05-12 09:49:50', '2026-05-12 09:49:50', NULL);
INSERT INTO public.product_faqs VALUES (167, 26, 'Chuột Logitech MX Master 4 có phù hợp cho công việc thiết kế và lập trình không?', 'Có, với cảm biến Darkfield 8000 DPI, bánh xe cuộn MagSpeed và thiết kế công thái học, sản phẩm rất phù hợp cho lập trình viên, designer và dân văn phòng chuyên nghiệp.', 3, true, '2026-05-12 09:49:50', '2026-05-12 09:49:50', NULL);
INSERT INTO public.product_faqs VALUES (148, 25, 'Màn hình ASUS TUF Gaming có những kích thước nào?', 'Dòng sản phẩm này có đa dạng kích thước từ màn hình tiêu chuẩn 24 inch, 25 inch, 27 inch cho đến màn hình siêu rộng 34 inch.', 0, true, '2026-05-06 07:57:15', '2026-05-13 15:17:09', '2026-05-13 15:17:09');
INSERT INTO public.product_faqs VALUES (149, 25, 'Tần số quét cao nhất của dòng màn hình này là bao nhiêu?', 'Tần số quét cao nhất ghi nhận được là 300Hz trên phiên bản 27 inch - 2K.', 1, true, '2026-05-06 07:57:15', '2026-05-13 15:17:09', '2026-05-13 15:17:09');
INSERT INTO public.product_faqs VALUES (150, 25, 'Sự khác biệt giữa tấm nền IPS và VA trên các mẫu này là gì?', 'Tấm nền IPS (thường ở bản 24, 25, 27 inch) cho màu sắc và góc nhìn tốt, trong khi tấm nền VA (thường ở bản 34 inch) mang lại độ tương phản sâu hơn.', 2, true, '2026-05-06 07:57:15', '2026-05-13 15:17:09', '2026-05-13 15:17:09');
INSERT INTO public.product_faqs VALUES (151, 25, 'Độ phân giải của các mẫu màn hình 34 inch là bao nhiêu?', 'Các mẫu 34 inch trong danh sách đều sở hữu độ phân giải cao chuẩn WQHD hoặc QWHD.', 3, true, '2026-05-06 07:57:15', '2026-05-13 15:17:09', '2026-05-13 15:17:09');
INSERT INTO public.product_faqs VALUES (152, 25, 'Tôi nên chọn phiên bản nào để chơi game bắn súng (FPS)?', 'Bạn nên chọn các phiên bản có tần số quét từ 240Hz đến 300Hz (như bản 27 inch FHD hoặc 2K) để có chuyển động mượt mà nhất.', 4, true, '2026-05-06 07:57:15', '2026-05-13 15:17:09', '2026-05-13 15:17:09');
INSERT INTO public.product_faqs VALUES (168, 26, 'MX Master 4 có cần cài phần mềm để sử dụng đầy đủ tính năng không?', 'Người dùng nên cài đặt Logi Options+ để tùy chỉnh nút bấm, tạo shortcut và tối ưu trải nghiệm sử dụng trên từng ứng dụng.', 4, true, '2026-05-12 09:49:50', '2026-05-12 09:49:50', NULL);
INSERT INTO public.product_faqs VALUES (169, 1, 'iPhone 15 Pro có mấy phiên bản dung lượng?', 'iPhone 15 Pro có 4 tùy chọn dung lượng gồm 128GB, 256GB, 512GB và 1TB.', 0, true, '2026-05-12 10:36:01', '2026-05-12 10:36:01', NULL);
INSERT INTO public.product_faqs VALUES (170, 1, 'iPhone 15 Pro dùng chip gì?', 'iPhone 15 Pro được trang bị chip A17 Pro với CPU 6 lõi, GPU 6 lõi và Neural Engine 16 lõi mạnh mẽ.', 1, true, '2026-05-12 10:36:01', '2026-05-12 10:36:01', NULL);
INSERT INTO public.product_faqs VALUES (171, 1, 'iPhone 15 Pro có chống nước không?', 'Máy đạt chuẩn IP68, có khả năng chống nước ở độ sâu tối đa 6 mét trong 30 phút.', 2, true, '2026-05-12 10:36:01', '2026-05-12 10:36:01', NULL);
INSERT INTO public.product_faqs VALUES (172, 1, 'iPhone 15 Pro có hỗ trợ sạc nhanh không?', 'Thiết bị hỗ trợ sạc nhanh, có thể sạc khoảng 50% pin trong 30 phút với củ sạc 20W trở lên.', 3, true, '2026-05-12 10:36:01', '2026-05-12 10:36:01', NULL);
INSERT INTO public.product_faqs VALUES (173, 1, 'Camera iPhone 15 Pro có tốt không?', 'Máy sở hữu camera chính 48MP, camera góc siêu rộng 12MP và tele 3x 12MP, phù hợp chụp ảnh chuyên nghiệp.', 4, true, '2026-05-12 10:36:01', '2026-05-12 10:36:01', NULL);
INSERT INTO public.product_faqs VALUES (174, 1, 'iPhone 15 Pro có mấy màu?', 'iPhone 15 Pro có 4 màu gồm Titan Đen, Titan Trắng, Titan Xanh và Titan Tự Nhiên.', 5, true, '2026-05-12 10:36:01', '2026-05-12 10:36:01', NULL);
INSERT INTO public.product_faqs VALUES (175, 27, 'Bàn phím E-DRA EK375W có hỗ trợ kết nối không dây không?', 'Có, bàn phím hỗ trợ 3 chế độ kết nối gồm USB Type-C, Bluetooth và Wireless 2.4GHz.', 0, true, '2026-05-12 10:55:28', '2026-05-12 10:59:08', '2026-05-12 10:59:08');
INSERT INTO public.product_faqs VALUES (176, 27, 'E-DRA EK375W có hot swap không?', 'Có, sản phẩm hỗ trợ hot swap giúp thay switch dễ dàng mà không cần hàn.', 1, true, '2026-05-12 10:55:28', '2026-05-12 10:59:08', '2026-05-12 10:59:08');
INSERT INTO public.product_faqs VALUES (177, 27, 'Pin của E-DRA EK375W dùng được bao lâu?', 'Pin 4000mAh có thể sử dụng khoảng 5–7 ngày tùy mức độ dùng và đèn RGB.', 2, true, '2026-05-12 10:55:28', '2026-05-12 10:59:08', '2026-05-12 10:59:08');
INSERT INTO public.product_faqs VALUES (178, 27, 'Bàn phím này có tương thích macOS không?', 'Có, tương thích với cả Windows và macOS.', 3, true, '2026-05-12 10:55:28', '2026-05-12 10:59:08', '2026-05-12 10:59:08');
INSERT INTO public.product_faqs VALUES (179, 27, 'E-DRA EK375W sử dụng loại switch gì?', 'Bàn phím dùng E-DRA Linear Custom Switch, cảm giác gõ mượt và nhẹ.', 4, true, '2026-05-12 10:55:28', '2026-05-12 10:59:08', '2026-05-12 10:59:08');
INSERT INTO public.product_faqs VALUES (180, 27, 'E-DRA EK375W có phù hợp chơi game không?', 'Có, bàn phím hỗ trợ anti-ghosting full keys, phù hợp chơi game và làm việc.', 5, true, '2026-05-12 10:55:28', '2026-05-12 10:59:08', '2026-05-12 10:59:08');
INSERT INTO public.product_faqs VALUES (181, 27, 'Bàn phím E-DRA EK375W có hỗ trợ kết nối không dây không?', 'Có, bàn phím hỗ trợ 3 chế độ kết nối gồm USB Type-C, Bluetooth và Wireless 2.4GHz.', 0, true, '2026-05-12 10:59:08', '2026-05-12 10:59:08', NULL);
INSERT INTO public.product_faqs VALUES (182, 27, 'E-DRA EK375W có hot swap không?', 'Có, sản phẩm hỗ trợ hot swap giúp thay switch dễ dàng mà không cần hàn.', 1, true, '2026-05-12 10:59:08', '2026-05-12 10:59:08', NULL);
INSERT INTO public.product_faqs VALUES (183, 27, 'Pin của E-DRA EK375W dùng được bao lâu?', 'Pin 4000mAh có thể sử dụng khoảng 5–7 ngày tùy mức độ dùng và đèn RGB.', 2, true, '2026-05-12 10:59:08', '2026-05-12 10:59:08', NULL);
INSERT INTO public.product_faqs VALUES (184, 27, 'Bàn phím này có tương thích macOS không?', 'Có, tương thích với cả Windows và macOS.', 3, true, '2026-05-12 10:59:08', '2026-05-12 10:59:08', NULL);
INSERT INTO public.product_faqs VALUES (185, 27, 'E-DRA EK375W sử dụng loại switch gì?', 'Bàn phím dùng E-DRA Linear Custom Switch, cảm giác gõ mượt và nhẹ.', 4, true, '2026-05-12 10:59:08', '2026-05-12 10:59:08', NULL);
INSERT INTO public.product_faqs VALUES (186, 27, 'E-DRA EK375W có phù hợp chơi game không?', 'Có, bàn phím hỗ trợ anti-ghosting full keys, phù hợp chơi game và làm việc.', 5, true, '2026-05-12 10:59:08', '2026-05-12 10:59:08', NULL);
INSERT INTO public.product_faqs VALUES (187, 28, 'Aula S99 có phải bàn phím cơ không?', 'Không, đây là bàn phím giả cơ (membrane) nhưng cho cảm giác gõ giống bàn phím cơ.', 0, true, '2026-05-12 11:07:22', '2026-05-12 11:07:22', NULL);
INSERT INTO public.product_faqs VALUES (188, 28, 'Aula S99 có kết nối Bluetooth không?', 'Có, hỗ trợ Bluetooth, 2.4GHz và cắm dây USB-C.', 1, true, '2026-05-12 11:07:22', '2026-05-12 11:07:22', NULL);
INSERT INTO public.product_faqs VALUES (189, 28, 'Aula S99 có phù hợp chơi game không?', 'Có, phù hợp chơi game phổ thông và làm việc hằng ngày.', 2, true, '2026-05-12 11:07:22', '2026-05-12 11:07:22', NULL);
INSERT INTO public.product_faqs VALUES (190, 28, 'Pin Aula S99 dùng được bao lâu?', 'Pin 2000mAh, thời gian dùng tùy đèn nền và cường độ sử dụng.', 3, true, '2026-05-12 11:07:22', '2026-05-12 11:07:22', NULL);
INSERT INTO public.product_faqs VALUES (191, 28, 'Aula S99 có dùng cho MacBook không?', 'Có, tương thích macOS và các thiết bị Bluetooth khác.', 4, true, '2026-05-12 11:07:22', '2026-05-12 11:07:22', NULL);
INSERT INTO public.product_faqs VALUES (192, 28, 'Aula S99 có hot swap không?', 'Không, bản giả cơ không hỗ trợ thay switch.', 5, true, '2026-05-12 11:07:22', '2026-05-12 11:07:22', NULL);
INSERT INTO public.product_faqs VALUES (193, 29, 'AULA F75 có hot swap không?', 'Có, hỗ trợ hot swap thay switch dễ dàng.', 0, true, '2026-05-12 11:14:19', '2026-05-12 11:14:19', NULL);
INSERT INTO public.product_faqs VALUES (194, 29, 'AULA F75 có kết nối không dây không?', 'Bản có dây chỉ hỗ trợ kết nối USB Type-C.', 1, true, '2026-05-12 11:14:19', '2026-05-12 11:14:19', NULL);
INSERT INTO public.product_faqs VALUES (195, 29, 'AULA F75 dùng switch gì?', 'Tùy bản, phổ biến là Outemu Red Switch.', 2, true, '2026-05-12 11:14:19', '2026-05-12 11:14:19', NULL);
INSERT INTO public.product_faqs VALUES (196, 29, 'AULA F75 có phù hợp chơi game không?', 'Có, hỗ trợ 1000Hz polling rate và anti-ghosting.', 3, true, '2026-05-12 11:14:19', '2026-05-12 11:14:19', NULL);
INSERT INTO public.product_faqs VALUES (197, 29, 'AULA F75 có dùng cho MacBook không?', 'Có, hỗ trợ macOS và Windows.', 4, true, '2026-05-12 11:14:19', '2026-05-12 11:14:19', NULL);
INSERT INTO public.product_faqs VALUES (198, 29, 'AULA F75 có núm xoay không?', 'Có, tích hợp núm xoay điều chỉnh âm lượng và media.', 5, true, '2026-05-12 11:14:19', '2026-05-12 11:14:19', NULL);
INSERT INTO public.product_faqs VALUES (199, 30, 'Logitech G304 có sạc được không?', 'Không, chuột dùng 1 pin AA thay thế.', 0, true, '2026-05-12 11:18:24', '2026-05-12 11:18:24', NULL);
INSERT INTO public.product_faqs VALUES (200, 30, 'G304 có dùng Bluetooth không?', 'Không, chỉ hỗ trợ kết nối LIGHTSPEED 2.4GHz qua receiver USB.', 1, true, '2026-05-12 11:18:24', '2026-05-12 11:18:24', NULL);
INSERT INTO public.product_faqs VALUES (201, 30, 'G304 có phù hợp chơi game FPS không?', 'Có, cảm biến HERO và polling rate 1000Hz rất phù hợp cho FPS.', 2, true, '2026-05-12 11:18:24', '2026-05-12 11:18:24', NULL);
INSERT INTO public.product_faqs VALUES (202, 30, 'Chuột G304 dùng được bao lâu?', 'Khoảng 250 giờ với 1 pin AA theo công bố hãng.', 3, true, '2026-05-12 11:18:24', '2026-05-12 11:18:24', NULL);
INSERT INTO public.product_faqs VALUES (203, 30, 'G304 có dùng cho MacBook không?', 'Có, hỗ trợ macOS nếu có cổng USB cho receiver.', 4, true, '2026-05-12 11:18:24', '2026-05-12 11:18:24', NULL);
INSERT INTO public.product_faqs VALUES (204, 30, 'G304 có nặng không?', 'Chuột nặng khoảng 99g khi lắp pin, khá nhẹ cho sử dụng lâu.', 5, true, '2026-05-12 11:18:24', '2026-05-12 11:18:24', NULL);
INSERT INTO public.product_faqs VALUES (205, 31, 'RAM XPG D50 có dùng cho laptop không?', 'Không, đây là RAM U-DIMM dành cho máy tính bàn.', 0, true, '2026-05-12 11:27:42', '2026-05-12 11:27:42', NULL);
INSERT INTO public.product_faqs VALUES (206, 31, 'RAM này có RGB không?', 'Có, hỗ trợ LED RGB đồng bộ mainboard.', 1, true, '2026-05-12 11:27:42', '2026-05-12 11:27:42', NULL);
INSERT INTO public.product_faqs VALUES (207, 31, 'RAM hỗ trợ ép xung không?', 'Có, hỗ trợ Intel XMP 2.0.', 2, true, '2026-05-12 11:27:42', '2026-05-12 11:27:42', NULL);
INSERT INTO public.product_faqs VALUES (208, 31, 'Nên mua 8GB hay 16GB?', '8GB đủ văn phòng, 16GB phù hợp gaming và đồ họa.', 3, true, '2026-05-12 11:27:42', '2026-05-12 11:27:42', NULL);
INSERT INTO public.product_faqs VALUES (153, 25, 'Màn hình ASUS TUF có hỗ trợ độ phân giải 2K không?', 'Có, dòng TUF cung cấp nhiều lựa chọn độ phân giải 2K (2560 x 1440) chủ yếu ở kích thước 27 inch với nhiều mức tần số quét khác nhau.', 5, true, '2026-05-06 07:57:15', '2026-05-13 15:17:09', '2026-05-13 15:17:09');
INSERT INTO public.product_faqs VALUES (338, 25, 'Màn hình ASUS TUF Gaming có những kích thước nào?', 'Dòng sản phẩm này có đa dạng kích thước từ màn hình tiêu chuẩn 24 inch, 25 inch, 27 inch cho đến màn hình siêu rộng 34 inch.', 0, true, '2026-05-13 15:17:09', '2026-05-13 15:17:09', NULL);
INSERT INTO public.product_faqs VALUES (339, 25, 'Tần số quét cao nhất của dòng màn hình này là bao nhiêu?', 'Tần số quét cao nhất ghi nhận được là 300Hz trên phiên bản 27 inch - 2K.', 1, true, '2026-05-13 15:17:09', '2026-05-13 15:17:09', NULL);
INSERT INTO public.product_faqs VALUES (340, 25, 'Sự khác biệt giữa tấm nền IPS và VA trên các mẫu này là gì?', 'Tấm nền IPS (thường ở bản 24, 25, 27 inch) cho màu sắc và góc nhìn tốt, trong khi tấm nền VA (thường ở bản 34 inch) mang lại độ tương phản sâu hơn.', 2, true, '2026-05-13 15:17:09', '2026-05-13 15:17:09', NULL);
INSERT INTO public.product_faqs VALUES (341, 25, 'Độ phân giải của các mẫu màn hình 34 inch là bao nhiêu?', 'Các mẫu 34 inch trong danh sách đều sở hữu độ phân giải cao chuẩn WQHD hoặc QWHD.', 3, true, '2026-05-13 15:17:09', '2026-05-13 15:17:09', NULL);
INSERT INTO public.product_faqs VALUES (342, 25, 'Tôi nên chọn phiên bản nào để chơi game bắn súng (FPS)?', 'Bạn nên chọn các phiên bản có tần số quét từ 240Hz đến 300Hz (như bản 27 inch FHD hoặc 2K) để có chuyển động mượt mà nhất.', 4, true, '2026-05-13 15:17:09', '2026-05-13 15:17:09', NULL);
INSERT INTO public.product_faqs VALUES (343, 25, 'Màn hình ASUS TUF có hỗ trợ độ phân giải 2K không?', 'Có, dòng TUF cung cấp nhiều lựa chọn độ phân giải 2K (2560 x 1440) chủ yếu ở kích thước 27 inch với nhiều mức tần số quét khác nhau.', 5, true, '2026-05-13 15:17:09', '2026-05-13 15:17:09', NULL);
