INSERT INTO public.product_faqs VALUES (374, 192, 'Câu hỏi thường gặp', 'Nguồn 1200W có đủ gánh cho VGA RTX 5090 khi làm việc cường độ cao không?|Hoàn toàn dư dả và an toàn. Bộ nguồn ROG Thor 1200W Platinum II đạt tiêu chuẩn ATX 3.1 mới nhất, trang bị sẵn cáp PCIe 5.0 (12V-2x6) chịu tải trực tiếp cho các dòng card thế hệ mới, đảm bảo hệ thống vận hành mượt mà ngay cả khi cả CPU và GPU cùng overclocking.|-|', 2, true, '2026-05-22 16:08:30', '2026-05-22 16:25:28', '2026-05-22 16:25:28');
