INSERT INTO public.product_faqs VALUES (376, 192, 'Câu hỏi thường gặp', 'Cấu hình PC 120 triệu này có đi kèm màn hình, bàn phím và chuột chưa?|Mức giá 120 triệu đồng được tối ưu tập trung toàn bộ vào hiệu năng của thùng máy (PC Case) cùng linh kiện khủng bên trong để phục vụ công việc đồ họa nặng. Mức giá này chưa bao gồm màn hình và các thiết thiết bị ngoại vi như chuột, bàn phím, tai nghe.|-|', 0, true, '2026-05-22 16:25:28', '2026-05-22 16:39:02', '2026-05-22 16:39:02');
INSERT INTO public.product_faqs VALUES (377, 192, 'Câu hỏi thường gặp', 'Hệ thống tản nhiệt nước AIO đi kèm có cần phải thay nước định kỳ không?|Tản nhiệt ASUS ROG RYUJIN III 360 là tản nhiệt nước dạng đóng (All-in-One) tuần hoàn khép kín được nhà sản xuất châm sẵn dung dịch làm mát cao cấp. Bạn hoàn toàn không cần thay nước hay bảo dưỡng chất lỏng trong suốt vòng đời sản phẩm, chỉ cần vệ sinh bụi bám ở quạt định kỳ.|-|', 1, true, '2026-05-22 16:25:28', '2026-05-22 16:39:02', '2026-05-22 16:39:02');
INSERT INTO public.product_faqs VALUES (378, 192, 'Câu hỏi thường gặp', 'Nguồn 1200W có đủ gánh cho VGA RTX 5090 khi làm việc cường độ cao không?|Hoàn toàn dư dả và an toàn. Bộ nguồn ROG Thor 1200W Platinum II đạt tiêu chuẩn ATX 3.1 mới nhất, trang bị sẵn cáp PCIe 5.0 (12V-2x6) chịu tải trực tiếp cho các dòng card thế hệ mới, đảm bảo hệ thống vận hành mượt mà ngay cả khi cả CPU và GPU cùng overclocking.|-|', 2, true, '2026-05-22 16:25:28', '2026-05-22 16:39:02', '2026-05-22 16:39:02');
INSERT INTO public.product_faqs VALUES (379, 192, 'Câu hỏi thường gặp', 'Chế độ bảo hành đối với bộ PC cao cấp này như thế nào?|Toàn bộ linh kiện chính trong bộ PC (Mainboard, CPU, VGA, RAM, SSD, Nguồn) đều được hưởng chế độ bảo hành chính hãng từ 36 tháng đến 60 tháng (tùy linh kiện). Khách hàng sẽ được hỗ trợ kỹ thuật tận nơi và áp dụng chính sách lỗi 1 đổi 1 trong vòng 30 ngày đầu tiên nếu có lỗi từ nhà sản xuất.|-|', 3, true, '2026-05-22 16:25:28', '2026-05-22 16:39:02', '2026-05-22 16:39:02');
INSERT INTO public.product_faqs VALUES (380, 192, 'Cấu hình PC 120 triệu này có đi kèm màn hình, bàn phím và chuột chưa?', 'Mức giá 120 triệu đồng được tối ưu tập trung toàn bộ vào hiệu năng của thùng máy (PC Case) cùng linh kiện khủng bên trong để phục vụ công việc đồ họa nặng. Mức giá này chưa bao gồm màn hình và các thiết bị ngoại vi như chuột, bàn phím, tai nghe.|-|-|', 0, true, '2026-05-22 16:39:02', '2026-05-23 16:53:16', '2026-05-23 16:53:16');
INSERT INTO public.product_faqs VALUES (381, 192, 'Hệ thống tản nhiệt nước AIO đi kèm có cần phải thay nước định kỳ không?', 'Tản nhiệt ASUS ROG RYUJIN III 360 là tản nhiệt nước dạng đóng (All-in-One) tuần hoàn khép kín được nhà sản xuất châm sẵn dung dịch làm mát cao cấp. Bạn hoàn toàn không cần thay nước hay bảo dưỡng chất lỏng trong suốt vòng đời sản phẩm, chỉ cần vệ sinh bụi bám ở quạt định kỳ.|-|-|', 1, true, '2026-05-22 16:39:02', '2026-05-23 16:53:16', '2026-05-23 16:53:16');
INSERT INTO public.product_faqs VALUES (382, 192, 'Nguồn 1200W có đủ gánh cho VGA RTX 5090 khi làm việc cường độ cao không?', 'Hoàn toàn dư dả và an toàn. Bộ nguồn ROG Thor 1200W Platinum II đạt tiêu chuẩn ATX 3.1 mới nhất, trang bị sẵn cáp PCIe 5.0 (12V-2x6) chịu tải trực tiếp cho các dòng card thế hệ mới, đảm bảo hệ thống vận hành mượt mà ngay cả khi cả CPU và GPU cùng overclocking.|-|-|', 2, true, '2026-05-22 16:39:02', '2026-05-23 16:53:16', '2026-05-23 16:53:16');
