INSERT INTO public.product_faqs VALUES (384, 192, 'Cấu hình PC 120 triệu này có đi kèm màn hình, bàn phím và chuột chưa?', 'Mức giá 120 triệu đồng được tối ưu tập trung toàn bộ vào hiệu năng của thùng máy (PC Case) cùng linh kiện khủng bên trong để phục vụ công việc đồ họa nặng. Mức giá này chưa bao gồm màn hình và các thiết bị ngoại vi như chuột, bàn phím, tai nghe.|-|-|', 0, true, '2026-05-23 16:53:16', '2026-05-23 16:53:55', '2026-05-23 16:53:55');
