INSERT INTO public.product_faqs VALUES (401, 192, 'Hệ thống tản nhiệt nước AIO đi kèm có cần phải thay nước định kỳ không?', 'Tản nhiệt ASUS ROG RYUJIN III 360 là tản nhiệt nước dạng đóng (All-in-One) tuần hoàn khép kín được nhà sản xuất châm sẵn dung dịch làm mát cao cấp. Bạn hoàn toàn không cần thay nước hay bảo dưỡng chất lỏng trong suốt vòng đời sản phẩm, chỉ cần vệ sinh bụi bám ở quạt định kỳ.|-|-|', 1, true, '2026-05-25 16:13:39', '2026-05-25 16:13:39', NULL);
INSERT INTO public.product_faqs VALUES (402, 192, 'Nguồn 1200W có đủ gánh cho VGA RTX 5090 khi làm việc cường độ cao không?', 'Hoàn toàn dư dả và an toàn. Bộ nguồn ROG Thor 1200W Platinum II đạt tiêu chuẩn ATX 3.1 mới nhất, trang bị sẵn cáp PCIe 5.0 (12V-2x6) chịu tải trực tiếp cho các dòng card thế hệ mới, đảm bảo hệ thống vận hành mượt mà ngay cả khi cả CPU và GPU cùng overclocking.|-|-|', 2, true, '2026-05-25 16:13:39', '2026-05-25 16:13:39', NULL);
INSERT INTO public.product_faqs VALUES (403, 192, 'Chế độ bảo hành đối với bộ PC cao cấp này như thế nào?', 'Toàn bộ linh kiện chính trong bộ PC (Mainboard, CPU, VGA, RAM, SSD, Nguồn) đều được hưởng chế độ bảo hành chính hãng từ 36 tháng đến 60 tháng (tùy linh kiện). Khách hàng sẽ được hỗ trợ kỹ thuật tận nơi và áp dụng chính sách lỗi 1 đổi 1 trong vòng 30 ngày đầu tiên nếu có lỗi từ nhà sản xuất.|-|-|', 3, true, '2026-05-25 16:13:39', '2026-05-25 16:13:39', NULL);


