INSERT INTO public.product_news VALUES (12, 23, 'Caviar ra mắt bộ sưu tập iPhone 17 Pro màu hồng sang trọng, nạm vàng và kim cương, giá lên tới hơn 500 triệu đồng', 'caviar-ra-mat-bo-suu-tap-iphone-17-pro-mau-hong-sang-trong-nam-vang-va-kim-cuong-gia-len-toi-hon-500-trieu-dong', '<div class="mb-[10px]  hidden w-full gap-[10px] w600:flex "><a class="flex h-fit w-fit items-center gap-[5px] rounded-[5px] bg-cps px-[8px] py-[5px] text-textWhite w600:px-[12px]" href="/sforum/tin-cong-nghe"><span class="text-sm font-[600] w600:text-base">Tin công nghệ</span></a></div><h1 class="m-[0px] hidden py-[10px] text-xl font-bold text-textGray w600:inline-block w600:text-2xl w900:text-3xl">Caviar ra mắt bộ sưu tập iPhone 17 Pro màu hồng sang trọng, nạm vàng và kim cương, giá lên tới hơn 500 triệu đồng</h1><div class="flex w-full flex-wrap items-center justify-between gap-[10px] py-[10px]"><div class="flex items-center gap-[5px]"><div class="h-[35px] w-[35px] rounded-[50%] border-[1px] border-[#ef1515] p-[2px] w600:h-[40px] w600:w-[40px]"><div class="relative h-full w-full rounded-[50%]"><img alt="Tiz , Tác giả Sforum - Trang tin công nghệ mới nhất" title="Tiz , Tác giả Sforum - Trang tin công nghệ mới nhất" loading="lazy" width="80" height="80" decoding="async" data-nimg="1" class="h-full w-full rounded-[50%] object-cover" style="color: transparent;" src="https://cdn-media.sforum.vn/storage/app/media/Profile CTV/46414680_1195062467317859_862356165189697536_n.jpg"></div></div><div class="flex flex-col gap-[2px]"><a class="text-sm font-[600] text-cps w600:text-base" href="/sforum/author/dungnguyen">Tiz </a><div class=" flex gap-[5px] text-[10px] font-[300] text-[#656565] w600:text-[11px]"><span class="flex items-center gap-[3px]"><span>Ngày cập nhật: 30/04/2026</span></span></div></div></div></div><div></div><div class="my-[15px] hidden w-full rounded-[8px] bg-[#f4f7ff] p-[10px] "><div class="my-[20px] h-[0px] w-full rounded-[12px] border-t-[1px] border-dashed border-[#919EAB3D] p-[12px]"></div><div class="mb-[10px] flex w-full flex-col items-end gap-[10px] w800:flex-row w800:items-start"><div class="mt-[10px]"></div><div class="mt-[10px] w-full"><div class="relative h-[14px] w-full rounded-[14px] bg-[#ff9099]"><div class="h-full rounded-[14px] bg-[#cd0017]"></div><div class="z-1 absolute top-[-10px] h-[30px] w-[30px] translate-x-[-20px] object-contain"></div><div class="absolute left-[50%] top-[50%] z-[2] w-[110%] translate-x-[-50%] translate-y-[-50%] text-center text-[11px] font-[800] text-[#fff]"></div></div></div><p class="w-full flex-1 border-[4px] border-[#d51f45] text-base font-[600]"></p><a class="sforum_view_all_product flex flex-shrink-0 items-center font-[600] !text-cps" href=""></a><div class="relative grid w-full grid-cols-2 justify-stretch gap-[5px] overflow-hidden w600:!grid-cols-3 w1000:!grid-cols-4"><div class="px-[2px]"><div class="swiper-slide p-[2px]"><div class="box-border block min-h-[60px] w-full overflow-hidden rounded-[8px] p-[10px] !text-textGray !no-underline shadow-gray hover:!text-cps hover:!no-underline"><div class="m-auto w-full max-w-[150px]"><div class="!m-[0px] aspect-1/1 w-full object-contain"></div></div><div class="line-clamp-2 min-h-[50px] w-full text-ellipsis text-start text-sm w600:text-base"></div><div class="mt-[5px] flex flex-wrap gap-[8px] line-through"></div></div></div></div></div><div class="my-[15px] flex w-full max-w-[200px] flex-shrink-0 flex-col items-center justify-center gap-[10px] overflow-hidden rounded-[10px] border-[1px] border-[#eee] p-[10px] w800:w-[35%] w800:flex-1 "></div><div class="gap-[20px] text-center text-xl font-[600]"></div><div class="aspect-video gap-[5px] rounded-[5px] bg-cps px-[8px] py-[5px] !text-textWhite"></div></div></div><div class="relative mt-[10px] w-full pb-[20px]"><div id="pin-table-content" class="sticky top-[var(--height-header)] z-[999] hidden max-h-[800px] w-[calc(100%+20px)] translate-x-[-10px] w600:w-[calc(100%+50px)] w600:translate-x-[-25px]"></div><div class="content-detail w-full text-textGray w600:mt-[10px]"><div><div class=""></div></div><div class="w-full"></div><div class="w-full"><p><strong>Giống như các sản phẩm tùy chỉnh khác của Caviar, <a href="https://cellphones.com.vn/iphone-17-pro.html">iPhone 17 Pro</a> Rose Collection sở hữu giá bán không hề rẻ.</strong></p>

<p>Caviar vừa cho ra mắt bộ sưu tập Rose Collection mới, bao gồm một loạt các mẫu <a href="https://cellphones.com.vn/mobile/apple/iphone-17.html" target="_blank">iPhone 17</a> Pro và Pro Max tùy chỉnh với thân máy màu hồng nhạt nổi bật. Các sản phẩm này được thiết kế dành cho những khách hàng coi trọng sự độc quyền, phong cách và sự sang trọng.</p>

<div style="text-align:center">
<img alt="Caviar ra mắt bộ sưu tập iPhone 17 Pro màu hồng sang trọng" height="674" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/Caviar-Sex-and-the-City-1.jpg" width="1200" title="Caviar ra mắt bộ sưu tập iPhone 17 Pro màu hồng sang trọng">
Caviar ra mắt bộ sưu tập <a href="https://cellphones.com.vn/mobile/apple.html" target="_blank">iPhone</a> 17 Pro màu hồng sang trọng

</div>

<p>Bộ sưu tập Rose bao gồm bốn thiết kế độc đáo: Sex and the City, Pink Lotus, Queen of Thorns và Ophelia. Caviar đã định hình mỗi mẫu với một chủ đề cụ thể lấy cảm hứng từ sự nữ tính, thời trang và sang trọng.</p>

<p>Model đầu tiên, Sex and the City, có giá khởi điểm 8,840 USD (khoảng 232 triệu đồng). Nó có phần thân màu hồng với họa tiết giày cao gót và logo Apple 3D làm từ vàng 18K. Caviar đã tạo ra thiết kế này để phản ánh phong cách thành thị và sự tự tin táo bạo, nhắm đến những người coi thời trang như một lối sống và bán giới hạn 99 chiếc.</p>

<div class="grid-cols-2 sforum-gallery">
<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/Caviar-Sex-and-the-City-2.jpg"></div>

<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/Caviar-Sex-and-the-City-3.jpg"></div>
</div>

<p style="text-align:center"><em>Phiên bản iPhone 17 Pro&nbsp;</em>Sex and the City</p>

<p>Mẫu đồng hồ Pink Lotus nổi bật là mẫu đắt nhất trong bộ sưu tập, với giá khởi điểm từ 20,270 USD (khoảng 534 triệu đồng). Caviar đã sử dụng vàng 999 mạ trên khung đồng hồ và đính 84 viên kim cương tự nhiên cùng các chi tiết khảm xà cừ.</p>

<p>Điện thoại còn có thiết kế tinh xảo lấy cảm hứng từ hoa sen, biểu tượng của sự thuần khiết và hài hòa trong văn hóa phương Đông. Chỉ có 14 chiếc được sản xuất, khiến nó trở thành một trong những phiên bản hiếm nhất trong bộ sưu tập.</p>

<div class="grid-cols-2 sforum-gallery">
<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/Caviar-Pink-Lotus-1.jpg"></div>

<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/Caviar-Pink-Lotus.jpg"></div>
</div>

<p style="text-align:center"><em>Phiên bản iPhone 17 Pro&nbsp;</em>Pink Lotus</p>

<p>Mẫu Queen of Thorns tập trung vào sự lãng mạn và thanh lịch, lấy cảm hứng từ thẩm mỹ Art Nouveau của Alphonse Mucha. Caviar đã phủ lên thiết bị những bông hồng men hồng và thêm logo Apple mạ vàng 999. Phiên bản này cũng được sản xuất giới hạn chỉ 99 chiếc và có giá khởi điểm 8,200 (khoảng 216 triệu đồng).</p>

<div class="grid-cols-2 sforum-gallery">
<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/Caviar-Queen-of-Thorns-1.jpg"></div>

<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/Caviar-Queen-of-Thorns.jpg"></div>
</div>

<p style="text-align:center"><em>Phiên bản iPhone 17 Pro&nbsp;</em>Queen of Thorns</p>

<p>Model cuối cùng, Ophelia, có giá khởi điểm 10,270 USD (khoảng 270 triệu đồng). Caviar đã thiết kế phiên bản này với các chi tiết mạ vàng, da bê cao cấp và men hồng nhạt. Caviar đặt tên mẫu đồng hồ theo nhân vật trong tác phẩm của Shakespeare để phản ánh vẻ đẹp tinh tế và nguồn cảm hứng thi ca, đồng thời bán giới hạn 19 chiếc.</p>

<p>Tất cả các mẫu trong Bộ sưu tập Rose đều đi kèm với bao bì cao cấp bao gồm hộp tương tác và chìa khóa mạ vàng 24K.</p>

<div class="grid-cols-2 sforum-gallery">
<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/Caviar-Ophelia-1.jpg"></div>

<div class="gallery-images" style="width:100%"><img alt="" src="https://cdn-media.sforum.vn/storage/app/media/trannghia/trannghia/1/Caviar-Ophelia.jpg"></div>
</div>

<p style="text-align:center"><em>Phiên bản iPhone 17 Pro&nbsp;</em>Ophelia</p>

<p>Theo mình, Rose Collection cho thấy Caviar tiếp tục biến iPhone thành món phụ kiện xa xỉ hơn là một chiếc <a href="https://cellphones.com.vn/mobile.html" target="_blank">smartphone</a> thông thường. Mức giá cực cao khiến sản phẩm này chỉ phù hợp với giới sưu tầm hoặc người muốn khẳng định đẳng cấp bằng những phiên bản iPhone độc bản.</p>

<p>Nguồn: Gizmochina</p>

