INSERT INTO public.videos VALUES (2, NULL, 'Review iPhone 17 Pro Max và iPhone 17 Pro', 'https://www.youtube.com/watch?v=hD3DbxrtMyI', 'https://i.ytimg.com/vi/hD3DbxrtMyI/hq720.jpg?sqp=-oaymwEnCNAFEJQDSFryq4qpAxkIARUAAIhCGAHYAQHiAQoIGBACGAY4AUAB&rs=AOn4CLCOfcYoiclU9cqD5hBBG4I89lFZMQ', 1, true, '2026-05-25 10:55:02', '2026-05-25 13:46:38', 4, 'Video review về iPhone 17 Pro Max và iPhone 17 Pro mang đến cái nhìn chi tiết về thiết kế mới, hiệu năng mạnh mẽ từ chip A19 Pro cùng hệ thống camera nâng cấp đáng chú ý. Người xem sẽ được trải nghiệm thực tế về màn hình, thời lượng pin, khả năng quay chụp và sự khác biệt giữa phiên bản Pro và Pro Max để dễ dàng lựa chọn mẫu máy phù hợp với nhu cầu sử dụng.');
INSERT INTO public.videos VALUES (1, 23, 'Introducing iPhone 17 Pro | Apple', 'https://www.youtube.com/watch?v=_-AS5DtDeqs', 'https://i.ytimg.com/vi/_-AS5DtDeqs/hq720.jpg?sqp=-oaymwEnCNAFEJQDSFryq4qpAxkIARUAAIhCGAHYAQHiAQoIGBACGAY4AUAB&rs=AOn4CLCiW9JuNSOTB80kduACda1LEjkyZg', 0, true, '2026-05-25 08:10:02', '2026-05-25 13:47:11', NULL, 'Video “Introducing iPhone 17 Pro | Apple” giới thiệu thế hệ iPhone Pro mới với thiết kế nhôm nguyên khối, chip A19 Pro mạnh mẽ cùng hệ thống tản nhiệt mới giúp nâng cao hiệu năng và thời lượng pin. Điểm nổi bật còn đến từ camera 48MP nâng cấp, zoom quang 8x, quay ProRes RAW và các tính năng video chuyên nghiệp dành cho nhà sáng tạo nội dung.');


